use std::time::Duration;

use rnacl_core::node::Node;

use crate::{args::node::add::AddNodeArgs, helper::resolve_ledger, reuse_node};

pub(super) fn dispatch(args: AddNodeArgs) -> anyhow::Result<()> {
    let node = Node::new(
        args.id.map_or(Default::default(), |id| id.into()),
        args.description,
        Default::default(),
        Duration::from_hours(1),
        Default::default(),
    );

    let ledger = resolve_ledger()?;
    ledger.add_node(&node)?;

    println!("{}", node.id());

    if !args.no_use {
        reuse_node::set(&ledger, node.id().clone(), None)?;
    }

    Ok(())
}

use crate::{
    args::node::edit::EditNodeArgs,
    helper::{resolve_explicit_or_reused_node, resolve_ledger},
};

pub(super) fn dispatch(args: EditNodeArgs) -> anyhow::Result<()> {
    let ledger = resolve_ledger()?;
    let mut node = resolve_explicit_or_reused_node(&ledger, args.node_id)?;

    if let Some(description) = args.description {
        *node.description_mut() = Some(description);
    }

    if args.unset_description {
        *node.description_mut() = None;
    }

    ledger.save_node(&node)?;

    println!("{}", node.id());

    Ok(())
}

use crate::{args::node::list::ListNodeArgs, helper::resolve_ledger};

pub(super) fn dispatch(_args: ListNodeArgs) -> anyhow::Result<()> {
    let ledger = resolve_ledger()?;
    let nodes = ledger.load_nodes()?;

    let node_id_width = nodes
        .iter()
        .map(|node| node.id().to_string().len())
        .max()
        .unwrap_or(0);
    for node in nodes {
        println!(
            "{:width$}  {}",
            node.id().to_string(),
            node.description()
                .clone()
                .unwrap_or_else(|| String::from("-")),
            width = node_id_width
        );
    }

    Ok(())
}

