use std::time::SystemTime;

use crate::{args::node::reuse::ReuseNodeArgs, helper::resolve_ledger, reuse_node, ui};

pub(super) fn dispatch(args: ReuseNodeArgs) -> anyhow::Result<()> {
    let ledger = resolve_ledger()?;

    match args {
        ReuseNodeArgs {
            node_id: Some(node_id),
            duration,
            ..
        } => {
            let node_id = ledger.resolve_node_id(&node_id)?;

            println!("{node_id}");

            reuse_node::set(
                &ledger,
                node_id,
                duration.map(|d| SystemTime::now() + d.into()),
            )?;
        }

        ReuseNodeArgs { unset: true, .. } => match reuse_node::get(&ledger)? {
            Some(node_id) => {
                println!("{node_id}");
                reuse_node::remove()?;
            }

            None => {
                ui::error("no reuse node set");
            }
        },

        ReuseNodeArgs { .. } => match reuse_node::get(&ledger)? {
            Some(node_id) => println!("{node_id}"),
            None => eprintln!("no reuse node set"),
        },
    }

    Ok(())
}

use crate::{
    args::node::show::ShowNodeArgs,
    helper::{resolve_explicit_or_reused_node, resolve_ledger},
};

pub(super) fn dispatch(args: ShowNodeArgs) -> anyhow::Result<()> {
    let ledger = resolve_ledger()?;
    let node = resolve_explicit_or_reused_node(&ledger, args.node_id)?;

    match args {
        ShowNodeArgs { raw: true, .. } => {
            println!("{}", serde_json::to_string_pretty(&node)?);
        }

        ShowNodeArgs { path: true, .. } => {
            println!("{}", ledger.node_path(node.id()).to_string_lossy());
        }

        _ => {
            println!(
                "{}\ndescription: {}\ndependencies: {}\nstages: {}",
                node.id(),
                node.description()
                    .clone()
                    .unwrap_or_else(|| String::from("none")),
                node.dependencies()
                    .iter()
                    .map(ToString::to_string)
                    .collect::<Vec<_>>()
                    .join(" "),
                node.pipeline().stages().len()
            );
        }
    }

    Ok(())
}

use std::io::{Read, stdin};

use rnacl_core::{registry, sample::batch::Batch};

use crate::{args::operation::eval::EvalOperationArgs, helper::resolve_ledger};

pub(super) fn dispatch(args: EvalOperationArgs) -> anyhow::Result<()> {
    let ledger = resolve_ledger()?;

    let options = match args.options {
        Some(serialized) => serde_json::from_str::<serde_json::Value>(&serialized)?,
        None => serde_json::Value::Null,
    };

    let operation = registry::resolve_op(&args.operation_id)?;

    let input = if !args.head {
        let mut buf = Vec::new();
        stdin().read_to_end(&mut buf)?;
        serde_json::from_slice::<Batch>(buf.as_slice())?
    } else {
        Batch::default()
    };

    let output = operation.eval(&ledger, input, options)?;

    println!("{}", serde_json::to_string_pretty(&output)?);

    Ok(())
}

use rnacl_core::registry;

use crate::args::operation::list::ListOperationArgs;

pub(super) fn dispatch(_args: ListOperationArgs) -> anyhow::Result<()> {
    let ops = registry::with_all_ops(|ops| ops.clone());

    let op_id_width = ops.iter().map(|op| op.0.len()).max().unwrap_or(0);
    for (id, op) in ops {
        println!("{:width$}  {}", id, op.description(), width = op_id_width);
    }

    Ok(())
}

