use std::{collections::HashMap, fs};

use glob::glob;
use rnacl_core::{
    ledger::Ledger,
    operation::{OperationError, TypedOperation},
    sample::{Sample, Trace, batch::Batch},
};
use serde::Deserialize;

pub(crate) struct HeadFileText;

#[derive(Deserialize)]
pub(crate) struct Options {
    files: Vec<String>,
}

impl TypedOperation for HeadFileText {
    type Options = Options;

    fn description(&self) -> &'static str {
        "Read text content from files. Option 'files' is an array of glob strings that are resolved to files and then read."
    }

    fn eval(
        &self,
        ledger: &Ledger,
        _input: Batch,
        options: Self::Options,
    ) -> Result<Batch, OperationError> {
        let base_path = ledger.container_dir();

        let paths = options
            .files
            .iter()
            .map(|pattern| {
                glob(
                    base_path
                        .join(pattern)
                        .to_str()
                        .expect("glob pattern does not appear to be UTF-8"),
                )
            })
            .collect::<Result<Vec<_>, _>>()
            .map_err(|err| OperationError::EvalError(format!("{}", err)))?
            .into_iter()
            .flat_map(|p| p.collect::<Vec<_>>())
            .collect::<Result<Vec<_>, _>>()
            .map_err(|err| OperationError::EvalError(format!("{}", err)))?;

        let files = paths
            .into_iter()
            .filter_map(|path| {
                fs::read_to_string(&path)
                    .map(|text| {
                        Sample::new(
                            Trace::new(HashMap::from([(
                                String::from("path"),
                                path.strip_prefix(&base_path)
                                    .expect("path is not relative to ledger container")
                                    .to_string_lossy()
                                    .to_string(),
                            )])),
                            text,
                        )
                    })
                    .ok()
            })
            .collect::<Vec<_>>();

        Ok(Batch::new(files))
    }
}

use std::time::Duration;

use rnacl_core::snapshot::diff::SamplePresence;

use crate::{
    args::audit::AuditArgs,
    helper::{resolve_explicit_or_reused_node_id, resolve_ledger},
    output, ui,
};

pub(super) fn dispatch(args: AuditArgs) -> anyhow::Result<()> {
    let ledger = resolve_ledger()?;
    let show_node_ids = args
        .node_id
        .into_iter()
        .map(|node_id| resolve_explicit_or_reused_node_id(&ledger, Some(node_id)))
        .collect::<anyhow::Result<Vec<_>>>()?;

    let audit = match args {
        AuditArgs { new: true, .. } => ledger.capture_snapshot(None)?,
        AuditArgs { cache: true, .. } => ledger.load_pending_snapshot().unwrap_or_default(),
        _ => ledger.capture_snapshot(Some(ledger.load_pending_snapshot().unwrap_or_default()))?,
    };
    let baseline = ledger.load_baseline_snapshot().unwrap_or_default();
    let diffs = audit.diff(baseline);

    if !args.dry_run {
        ledger.save_pending_snapshot(audit)?;
    }

    let mut unacked_nodes: usize = 0;
    let mut oldest_cache_age = Duration::ZERO;

    for (node_id, (diff, dependency_diffs)) in diffs {
        let cache_age = diff
            .after()
            .as_ref()
            .map(|batch| batch.created().elapsed())
            .transpose()?;
        let sample_diffs = diff.sample_diffs();
        let mut attributes = Vec::<String>::new();
        let mut needs_resolve = false;

        if sample_diffs.iter().any(|(_, p)| p != &SamplePresence::Both) {
            needs_resolve = true;
            attributes.push(format!(
                "dirty ({})",
                output::display_dirtiness(sample_diffs.iter().map(|(_, p)| p).collect::<Vec<_>>())
            ));
        }

        let stale_deps = dependency_diffs
            .into_iter()
            .map(|(node_id, diff)| (node_id, diff.sample_diffs()))
            .filter(|(_, samples)| samples.iter().any(|(_, p)| p != &SamplePresence::Both))
            .collect::<Vec<_>>();

        if !stale_deps.is_empty() {
            needs_resolve = true;
            attributes.push(format!(
                "stale ({} across {})",
                output::display_dirtiness(
                    stale_deps
                        .iter()
                        .flat_map(|(_, p)| p)
                        .map(|(_, p)| p)
                        .collect::<Vec<_>>()
                ),
                stale_deps.len()
            ));
        }

        if let Some(age) = cache_age
            && age.as_secs() > 0
        {
            oldest_cache_age = oldest_cache_age.max(age);
            attributes.push(format!(
                "cache ({})",
                humantime::format_duration(Duration::from_secs(age.as_secs()))
            ));
        }

        if needs_resolve {
            unacked_nodes += 1;
        }

        if needs_resolve && (show_node_ids.is_empty() || show_node_ids.contains(&node_id)) {
            println!("{}: {}", node_id, attributes.join(", "));

            if args.expand_diff {
                for sample_diff in sample_diffs
                    .iter()
                    .filter(|(_, p)| p != &SamplePresence::Both)
                {
                    println!("{}", output::display_sample_diff(sample_diff))
                }
            }

            if args.expand_stale {
                for stale_dep in stale_deps {
                    println!(
                        "    stale over {}: dirty ({})",
                        stale_dep.0,
                        output::display_dirtiness(
                            stale_dep.1.iter().map(|(_, p)| p).collect::<Vec<_>>()
                        )
                    );
                    if args.expand_diff {
                        for sample_diff in stale_dep
                            .1
                            .iter()
                            .filter(|(_, p)| p != &SamplePresence::Both)
                        {
                            println!("{}", output::display_sample_diff(sample_diff))
                        }
                    }
                }
            }
        }
    }

    if oldest_cache_age.as_secs() > 0 {
        ui::warn(format!(
            "cache is up to {} old",
            humantime::format_duration(Duration::from_secs(oldest_cache_age.as_secs()))
        ));
    }

    match unacked_nodes {
        0 => println!("ok!"),
        amount => println!("{amount} not ack'd"),
    }

    Ok(())
}

